#include <stdio.h>
#include <limits.h>
#define MOD 1000000007
#define MAXN 100
#define MAXM 1000000
#define MAXQ 1000000000000000000
int minWeight[MAXN + 1];
int main() {
    int N, C, M;
    scanf("%d %d %d", &N, &C, &M);
    int A[N], W[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &A[i], &W[i]);
    }
    for (int i = 0; i <= C; i++) {
        minWeight[i] = INT_MAX;
    }
    minWeight[0] = 0;
    for (int i = 1; i <= C; i++) {
        for (int j = 0; j < N; j++) {
            if (i >= A[j]) {
                minWeight[i] = (minWeight[i] < minWeight[i - A[j]] + W[j]) ? minWeight[i] : minWeight[i - A[j]] + W[j];
            }
        }
    }
    for (int i = 0; i < M; i++) {
        long long Q;
        scanf("%lld", &Q);
        if (Q > C) {
            printf("-1\n");
        } else {
            printf("%d\n", minWeight[Q % (MOD)] % MOD);
        }
    }
    return 0;
}

