import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int C = sc.nextInt();
        int M = sc.nextInt();
        int[] A = new int[N];
        int[] W = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
            W[i] = sc.nextInt();
        }
        int[] minWeight = new int[C + 1];
        for (int i = 0; i <= C; i++) {
            minWeight[i] = Integer.MAX_VALUE;
        }
        minWeight[0] = 0;
        for (int i = 1; i <= C; i++) {
            for (int j = 0; j < N; j++) {
                if (i >= A[j]) {
                    minWeight[i] = Math.min(minWeight[i], minWeight[i - A[j]] + W[j]);
                }
            }
        }
        for (int i = 0; i < M; i++) {
            long Q = sc.nextLong();
            if (Q > C) {
                System.out.println(-1);
            } else {
                System.out.println(minWeight[(int) (Q % 1000000007)] % 1000000007);
            }
        }
    }
}

